const input = $items("Set Input Defaults")[0].json;
const base = {
  project_name: input.project_name,
  neo4j_user: input.neo4j_user,
  neo4j_password: input.neo4j_password,
  neo4j_url: input.neo4j_url
};
const raw = $json.response !== undefined ? $json.response : ($json.body !== undefined ? $json.body : $json);
let cypherText = '';
if (typeof raw === 'string') {
  cypherText = raw;
} else if (raw && typeof raw === 'object' && typeof raw.response === 'string') {
  cypherText = raw.response;
} else {
  cypherText = JSON.stringify(raw);
}
cypherText = cypherText.replace(/```(?:cypher)?\s*/gi, '').replace(/```/g, '').trim();

function fixOutsideQuotes(str) {
  const parts = str.split("'");
  for (let i = 0; i < parts.length; i += 2) {
    parts[i] = parts[i].replace(/\)\)+/g, ')');
    parts[i] = parts[i].replace(/\}\}+/g, '}');
    parts[i] = parts[i].replace(/\]\}/g, ']');
  }
  return parts.join("'");
}

function hasValidNesting(str) {
  const u = str.replace(/'[^']*'/g, '');
  const stack = [];
  const opn = {'(':')','{':'}','[':']'};
  for (const c of u) {
    if (opn[c]) stack.push(c);
    else if (c === ')' || c === '}' || c === ']') {
      if (!stack.length || opn[stack.pop()] !== c) return false;
    }
  }
  return !stack.length;
}

const mergeChunks = cypherText.split(/(?=MERGE\s)/i).map(s => s.trim()).filter(s => /^MERGE\s/i.test(s));
const cleaned = [];
for (const chunk of mergeChunks) {
  let s = chunk;
  if (/MERME|MERX|MER:|MER\s*\{|LexicalForm|LexicalBody|LexicalHead|LexicalRule|LLEX|MERGEMINUS|BVar|:Lex\s/i.test(s)) break;
  const sq = (s.match(/'/g) || []).length;
  if (sq % 2 !== 0) continue;
  s = fixOutsideQuotes(s);
  if (!/^MERGE\s*\(/i.test(s)) continue;
  if (!hasValidNesting(s)) continue;
  const unquoted = s.replace(/'[^']*'/g, '');
  if (/-\[/.test(unquoted) && !/\]->\(\w+/.test(unquoted)) continue;
  cleaned.push(s);
}
if (!cleaned.length) {
  throw new Error('No valid MERGE after cleanup. Raw (first 500): ' + cypherText.slice(0, 500));
}
const unique = [...new Set(cleaned)];
const varDefs = new Map();
const otherNodes = [];
const relMerges = [];
for (const stmt of unique) {
  const stripped = stmt.replace(/'[^']*'/g, '');
  if (/-\[/.test(stripped)) { relMerges.push(stmt); continue; }
  const m = stmt.match(/^MERGE\s*\((\w+)(:\w+)\s*(\{[^}]+\})\)\s*(.*)/);
  if (m) {
    const vn = m[1], label = m[2], props = m[3], rest = (m[4] || '').trim();
    if (!varDefs.has(vn)) { varDefs.set(vn, { label, props, sets: new Set() }); }
    if (/^SET\s+/i.test(rest)) {
      const setPart = rest.replace(/^SET\s+/i, '').trim();
      const assigns = setPart.split(/,(?=(?:[^']*'[^']*')*[^']*$)/);
      for (const a of assigns) { if (a.trim()) varDefs.get(vn).sets.add(a.trim()); }
    }
  } else { otherNodes.push(stmt); }
}
const consolidated = [];
for (const [vn, info] of varDefs) {
  let line = 'MERGE (' + vn + info.label + ' ' + info.props + ')';
  if (info.sets.size > 0) { line += ' SET ' + [...info.sets].join(', '); }
  consolidated.push(line);
}
const finalCypher = [...consolidated, ...otherNodes, ...relMerges].join('\n');
return [{ json: { ...base, cypher: finalCypher } }];

const cypher = $json.cypher || '';
const project = $json.project_name || 'default-project';

const postProcess = [
  "MATCH (n) WHERE (n:Class OR n:DatatypeProperty OR n:ObjectProperty) AND n.graph IS NULL SET n.graph = 'OntoGraph', n.project = $project",
  "WITH 1 AS dummy",
  "MATCH (n) WHERE (n:Rule OR n:Atom OR n:Builtin OR n:Var OR n:Literal) AND n.graph IS NULL SET n.graph = 'Metagraph', n.project = $project",
  "WITH 1 AS dummy2",
  "MATCH (n) WHERE n.graph IS NULL SET n.graph = 'Metagraph', n.project = $project"
].join('\n');
return [{
  json: {
    project_name: $json.project_name,
    neo4j_user: $json.neo4j_user,
    neo4j_password: $json.neo4j_password,
    neo4j_url: $json.neo4j_url,
    cypher: cypher,
    postProcess: postProcess
  }
}];

const payload = $items("Prepare Graph Payload")[0].json;
const cypher = payload.cypher || '';
const mergeCount = (cypher.match(/MERGE/gi) || []).length;
return [{
  json: {
    status: "ok",
    project: payload.project_name,
    database: "neo4j",
    graphs: { ontology: "OntoGraph", rules: "Metagraph" },
    counts: { merge_statements: mergeCount },
    cypher: cypher
  }
}];
